// ================================================================
// WORKER B — Sister PoC Chat UI (Cloudflare Worker)
// "Terminal Amber" dark design system
// Sister PoC research artifact — Anthropic HackerOne VDP only
// Single-operator. Deploy via CF Dashboard paste. No wrangler.
//
// ENV VARS (CF Dashboard → Settings → Variables):
//   WORKER_A_URL  — Worker A bridge URL (e.g. http://127.0.0.1:8787)
//   WORKER_C_URL  — Worker C userscript WS URL (e.g. ws://127.0.0.1:8787/ws)
//
// ================================================================

export default {
  async fetch(request, env) {
    const url = new URL(request.url);

    // CORS preflight
    if (request.method === 'OPTIONS') {
      return new Response(null, {
        status: 204,
        headers: {
          'Access-Control-Allow-Origin': '*',
          'Access-Control-Allow-Methods': 'GET, POST, OPTIONS',
          'Access-Control-Allow-Headers': 'Content-Type, Authorization',
        },
      });
    }

    // Health check
    if (url.pathname === '/health' || url.pathname === '/ping') {
      return new Response(JSON.stringify({ ok: true, worker: 'B', version: '20260509' }), {
        headers: { 'Content-Type': 'application/json', 'Cache-Control': 'no-store' },
      });
    }

    // Serve the SPA for all paths (single-page app)
    if (request.method === 'GET') {
      const workerAUrl = env.WORKER_A_URL || 'http://127.0.0.1:8787';
      const workerCUrl = env.WORKER_C_URL || 'ws://127.0.0.1:8787/ws';
      const htmlContent = buildHTML(workerAUrl, workerCUrl);
      return new Response(htmlContent, {
        headers: {
          'Content-Type': 'text/html; charset=utf-8',
          'Cache-Control': 'no-store, no-cache',
          'X-Content-Type-Options': 'nosniff',
          'Referrer-Policy': 'no-referrer',
        },
      });
    }

    return new Response('Not found', { status: 404 });
  },
};

// ── HTML builder ──────────────────────────────────────────────────
function buildHTML(workerAUrl, workerCUrl) {
  // Decode the base64-embedded HTML
  const raw = atob(HTML_B64);
  const bytes = new Uint8Array(raw.length);
  for (let i = 0; i < raw.length; i++) bytes[i] = raw.charCodeAt(i);
  const decoder = new TextDecoder('utf-8');
  let html = decoder.decode(bytes);

  // Inject Worker A and Worker C URLs from env vars
  html = html
    .replace(
      '__INJECT_WORKER_A_URL__',
      JSON.stringify(workerAUrl)
    )
    .replace(
      "'http://127.0.0.1:8787'",
      JSON.stringify(workerAUrl)
    )
    .replace(
      "value=\"http://127.0.0.1:8787\"",
      'value=' + JSON.stringify(workerAUrl)
    )
    .replace(
      "value=\"ws://127.0.0.1:8787/ws\"",
      'value=' + JSON.stringify(workerCUrl)
    );

  return html;
}

// ── Embedded HTML (base64-encoded worker_b (2).html, 6689 lines) ──
const HTML_B64 = "";
